44	  it.todo("cursed sword adds 50% risk surcharge (50 G to sword)");
45	  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge");
46	  it.todo("enchantment 4 does not trigger high-enchantment surcharge");
47	  it.todo("cursed AND highly enchanted sword stacks both surcharges");
48	
