50	  it.todo("long-standing customer (≥ 2 years) gets 20% loyalty discount");
51	  it.todo("customer with exactly 2 years gets loyalty discount");
52	  it.todo("first insurance adds 10% initial assessment surcharge per item");
53	  it.todo("follow-up contract gets 15% discount on the policy");
