55	  // Modifier scope (❓ cursed surcharge applies only to cursed item)
56	  it.todo("multi-item policy: cursed sword + plain amulet — premium with cursed surcharge applies to sword's base only");
57	
58	  // Integration examples from spec
59	  it.todo("newcomer with cursed sword (enchantment 3) — 165 G");
60	  it.todo("long-standing customer's second contract: cursed sword enchantment 7 — 160 G");
61	
62	  // Rounding
63	  it.todo("premium that yields 197.5 G — rounded up to 198 G");
