66	  it.todo("regular sword (steel, enchantment 3), damage 500 G — payout 400 G");
67	  it.todo("damage to a rune (insurance value 250 G), damage 200 G — payout 100 G");
68	
69	  // Claim — deductible per damage event
70	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) — payout 600 G (deductible per item)");
71	
72	  // Claim — high enchantment clause
73	  it.todo("steel sword enchantment 9, damage 1000 G — payout 400 G (50% then deductible)");
74	
75	  // Claim — dragon material clause
